import sys
from typing import List

class Solution:
    def solve(self, V: int, edges: List[List[int]]) -> List[List[int]]:
        graph = [[] for _ in range(V)]
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        disc = [float('inf')] * V
        low = [float('inf')] * V
        parent = [-1] * V
        bridges = []
        time = 0

        def dfs(node):
            nonlocal time
            disc[node] = time
            low[node] = time
            time += 1
            for neighbor in graph[node]:
                if disc[neighbor] == float('inf'):
                    parent[neighbor] = node
                    dfs(neighbor)
                    low[node] = min(low[node], low[neighbor])
                    if low[neighbor] > disc[node]:
                        bridges.append([min(node, neighbor), max(node, neighbor)])
                elif neighbor != parent[node]:
                    low[node] = min(low[node], disc[neighbor])

        for i in range(V):
            if disc[i] == float('inf'):
                dfs(i)

        return sorted(bridges)

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        V, E = map(int, [next(it), next(it)])
        edges = [[int(next(it)), int(next(it))] for _ in range(E)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(V, edges)
    for bridge in ans:
        print(*bridge)

