#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<pair<int, int>> solve(int V, vector<vector<int>>& edges) {
        vector<vector<int>> graph(V);
        for (auto& edge : edges) {
            int u = edge[0], v = edge[1];
            graph[u].push_back(v);
            graph[v].push_back(u);
        }

        vector<int> disc(V, INT_MAX);
        vector<int> low(V, INT_MAX);
        vector<int> parent(V, -1);
        vector<pair<int, int>> bridges;
        int time = 0;

        function<void(int)> dfs = [&](int node) {
            disc[node] = time;
            low[node] = time;
            time++;
            for (int neighbor : graph[node]) {
                if (disc[neighbor] == INT_MAX) {
                    parent[neighbor] = node;
                    dfs(neighbor);
                    low[node] = min(low[node], low[neighbor]);
                    if (low[neighbor] > disc[node]) {
                        bridges.emplace_back(min(node, neighbor), max(node, neighbor));
                    }
                } else if (neighbor != parent[node]) {
                    low[node] = min(low[node], disc[neighbor]);
                }
            }
        };

        for (int i = 0; i < V; i++) {
            if (disc[i] == INT_MAX) {
                dfs(i);
            }
        }

        sort(bridges.begin(), bridges.end());
        return bridges;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (int i = 0; i < E; i++) cin >> edges[i][0] >> edges[i][1];
    Solution sol;
    auto ans = sol.solve(V, edges);
    for (auto& bridge : ans) {
        cout << bridge.first << " " << bridge.second << "\n";
    }
    return 0;
}
